import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CurrencyData {
  pair: string;
  currentRate: number;
  change: number;
  changePercent: number;
  weeklyTrend: number[];
}

export default function Widget() {
  const currencyData = response.data.data as CurrencyData;
  const { pair, currentRate, change, changePercent, weeklyTrend } = currencyData;
  const isPositive = change >= 0;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Currency Pair
            </Typography>
            <Typography variant="h5" fontWeight={700} sx={{ color: '#FF5722' }}>
              {pair}
            </Typography>
            <Typography variant="h6" fontWeight={600} sx={{ color: isPositive ? '#10B981' : '#EF4444' }}>
              {currentRate} {isPositive ? '+' : ''}{change} ({changePercent}%)
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: weeklyTrend,
                  color: '#03A9F4',
                  label: 'Weekly Trend',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  data: weeklyTrend.map((_, i) => i),
                  id: 'days',
                  hide: true,
                },
              ]}
              yAxis={[{ id: 'rate' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                hide={true}
              />
              <ChartsYAxis
                axisId="rate"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
